const ticket = $('Support Query Form').first().json;
const faqLines = items
  .filter(item => item.json.Question && item.json.Answer)
  .map(item => `Q: ${item.json.Question}\nA: ${item.json.Answer}`)
  .join('\n\n');
return [{ json: { query: ticket.query, requestId: String(Date.now()), receivedAt: new Date().toISOString(), faqContext: faqLines } }];

const form = $('Support Query Form').first().json;
const faq = $('Format FAQ Context').first().json;
const classifiedRaw = $('Classify & Draft Response').first().json;
const classified = classifiedRaw.output || classifiedRaw;
const scoredRaw = $input.first().json;
const scored = scoredRaw.output || scoredRaw;

return [{ json: {
  requestId: faq.requestId,
  receivedAt: faq.receivedAt,
  query: form.query,
  category: classified.category,
  draft_response: classified.draft_response,
  source_used: classified.source_used,
  confidence_score: Number(scored.confidence_score),
  risk_flag: scored.risk_flag,
  risk_category: scored.risk_category,
  reasoning: scored.reasoning
} }];
